#!/usr/bin/env python3
# -*- coding: utf-8 -*-
# build_site.py - erzeugt die drei Visualisierungsseiten von Norman Wagner:
#   collaboration-network.html   (Koautoren-Netzwerk; Quelle: index.html)
#   collaboration-worldmap.html  (Koautoren je Land + Klick-Liste; Quelle: index.html)
#   citation-worldmap.html       (zitierende Arbeiten je Land + Klick-Liste; Quelle: OpenAlex)
#
# Aufruf:  python3 build_site.py
# Voraussetzungen: Python 3.8+ (nur Standardbibliothek), Internet (OpenAlex + CDN-Bibliotheken).
# Die HTML-Layouts sind als base64-Vorlagen eingebettet; Bibliotheken (D3/TopoJSON/Weltkarte)
# und alle Daten werden zur Laufzeit injiziert -> die Ausgabedateien sind eigenstaendig.

import base64, json, re, sys, time, unicodedata, urllib.parse, urllib.request
from collections import Counter, defaultdict

# ---------- Konfiguration ----------
INDEX_HTML = "index.html"
AUTHOR_ID  = "A5030053078"
MAILTO     = "norman.wagner@posteo.com"
URL_WORLD  = "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json"
URL_D3     = "https://cdn.jsdelivr.net/npm/d3@7/dist/d3.min.js"
URL_TOPO   = "https://cdn.jsdelivr.net/npm/topojson-client@3/dist/topojson-client.min.js"
URL_ISO    = "https://cdn.jsdelivr.net/npm/world-countries@5/countries.json"
OUT_NET    = "collaboration-network.html"
OUT_COLLAB = "collaboration-worldmap.html"
OUT_CIT    = "citation-worldmap.html"

# ---------- eingebettete Vorlagen ----------
NET_TPL_B64    = ""
COLLAB_TPL_B64 = ""
CIT_TPL_B64    = ""
def tpl(b): return base64.b64decode(b).decode("utf-8")

# ---------- HTTP ----------
def http_get(url, as_json=True, tries=6):
    last=None
    for i in range(tries):
        req=urllib.request.Request(url, headers={"User-Agent":"build-site (mailto:"+MAILTO+")"})
        try:
            with urllib.request.urlopen(req, timeout=90) as r:
                raw=r.read()
            return json.loads(raw) if as_json else raw.decode("utf-8")
        except urllib.error.HTTPError as e:
            last=e
            if e.code in (429,500,502,503):
                w=2*(i+1); print("  ... "+str(e.code)+", warte "+str(w)+"s", file=sys.stderr); time.sleep(w); continue
            raise
        except urllib.error.URLError as e:
            last=e; time.sleep(2*(i+1))
    raise RuntimeError("Abruf fehlgeschlagen: "+url+" / "+str(last))

def oa(path):
    sep="&" if "?" in path else "?"
    return http_get("https://api.openalex.org"+path+sep+"mailto="+MAILTO)

def short_id(u): return u.rsplit("/",1)[-1]

# ---------- Namens- und Laenderlogik ----------
_REPL={"ue":"u"}  # placeholder, real map below
FMAP={"\u00fc":"u","\u00f6":"o","\u00e4":"a","\u00df":"ss","\u0161":"s","\u00e9":"e","\u00e8":"e","\u00f3":"o","\u00e1":"a","\u00ed":"i","\u00e7":"c"}
def fold(s):
    s=s.strip().lower()
    for k,v in FMAP.items(): s=s.replace(k,v)
    return "".join(c for c in unicodedata.normalize("NFKD",s) if not unicodedata.combining(c))
def parse_author(tok):
    raw=re.sub("<[^>]+>","",tok).strip()
    p=raw.split()
    if not p: return None,None
    fi=fold(p[0])[:1]; lf=fold(p[-1])
    if "henningsen" in lf: lf="felix-henningsen"
    if "lesoille" in lf: lf="delepine-lesoille"
    return fi+"|"+lf, raw

CITY_COUNTRY={"Weimar":"Germany","Karlsruhe":"Germany","Hannover":"Germany","Leipzig":"Germany","Gie\u00dfen":"Germany","Frankfurt":"Germany","Jena":"Germany","Ilmenau":"Germany","Berlin":"Germany","Heidelberg":"Germany","Clausthal":"Germany","Bochum":"Germany","Brisbane":"Australia","Paris":"France"}
ID_LOC={"n|wagner":"Weimar","r|wagner":"Weimar","f|schmidt":"Leipzig","v|schmidt":"Weimar","k|heide":"Jena","g|heide":"Jena","m|schwing":"Brisbane"}
SUR_LOC={"scheuermann":"Brisbane","bore":"Brisbane","karlovsek":"Brisbane","chen":"Brisbane","bittner":"Brisbane","bhuyan":"Brisbane","murgan":"Brisbane","mishra":"Brisbane","williams":"Brisbane","muhlhaus":"Brisbane","cai":"Brisbane","serna":"Brisbane","speer":"Brisbane","pascal":"Brisbane","serati":"Brisbane","kalbani":"Brisbane","shen":"Brisbane","yan":"Brisbane","gonzales":"Brisbane","fan":"Brisbane","braga":"Brisbane","baumgartl":"Brisbane","lockington":"Brisbane","torres":"Brisbane","brierre":"Brisbane","emmerich":"Karlsruhe","bieberstein":"Karlsruhe","becker":"Karlsruhe","schlaeger":"Karlsruhe","hubner":"Karlsruhe","triantafyllidis":"Karlsruhe","sokoll":"Karlsruhe","schimmer":"Karlsruhe","loewer":"Hannover","igel":"Hannover","gunther":"Hannover","martin":"Hannover","kruschwitz":"Hannover","minnich":"Hannover","bumberger":"Leipzig","mai":"Leipzig","lunenschloss":"Leipzig","schennen":"Leipzig","landmark":"Leipzig","kogler":"Leipzig","zacharias":"Leipzig","wollschlager":"Leipzig","rucker":"Leipzig","birnstiel":"Leipzig","geiling":"Leipzig","hohfeld":"Leipzig","schikowsky":"Leipzig","lauer":"Gie\u00dfen","felix-henningsen":"Gie\u00dfen","vashev":"Gie\u00dfen","pollmann":"Gie\u00dfen","bagdassarov":"Frankfurt","bark-zollmann":"Jena","deubener":"Jena","topfer":"Ilmenau","sachs":"Ilmenau","kmec":"Ilmenau","schilling":"Ilmenau","khan":"Ilmenau","thess":"Ilmenau","scherzberg":"Ilmenau","rauschenbach":"Ilmenau","bonitz":"Ilmenau","lorek":"Berlin","revil":"Paris","robinet":"Paris","coelho":"Paris","delepine-lesoille":"Paris","taillade":"Paris","six":"Paris","daout":"Paris","placko":"Paris","coperey":"Paris","honorio":"Paris","bohleber":"Heidelberg","eisen":"Heidelberg","mulder":"Bochum","leschik":"Clausthal","behrens":"Clausthal","frischat":"Clausthal","reinholz":"Clausthal","geissler":"Clausthal","wiedenbeck":"Clausthal","kupfer":"Weimar","trinks":"Weimar","noack":"Weimar","witt":"Weimar","janabi":"Weimar","wuttke":"Weimar","hailemariam":"Weimar","shrestha":"Weimar","sembdner":"Weimar","uschmann":"Weimar","kuhne":"Weimar","knoblauch":"Weimar","mueller":"Weimar","muller":"Weimar","gruse":"Weimar","wilting":"Weimar","al-janabi":"Weimar"}
# aktuelle Affiliationen (Sonderfaelle), die von der Gruppe abweichen:
OVERRIDE={"j|mai":"Canada","z|chen":"China","e|placencia-gomez":"Slovenia"}
def country_of(key):
    if key in OVERRIDE: return OVERRIDE[key]
    c=ID_LOC.get(key) or SUR_LOC.get(key.split("|",1)[1])
    return CITY_COUNTRY.get(c) if c else None

# ---------- index.html parsen ----------
def parse_index():
    html=open(INDEX_HTML,encoding="utf-8").read()
    arts=re.findall(r'<article class="pub"[^>]*data-year="(\d+)"[^>]*>(.*?)</article>', html, re.S)
    works=[]; paper_keys=[]; namecount=defaultdict(Counter)
    for year,body in arts:
        a=re.search(r'<span class="auth">(.*?)</span>', body, re.S)
        t=re.search(r'<span class="ttl">(.*?)</span>', body, re.S)
        v=re.search(r'<span class="ven">(.*?)</span>', body, re.S)
        doi=re.search(r'<a class="doi" href="([^"]+)"', body)
        anya=re.search(r'<a [^>]*href="([^"]+)"', body)
        link=doi.group(1) if doi else (anya.group(1) if anya else "")
        def strip(x): return re.sub("<[^>]+>","",x).strip()
        works.append({"y":int(year),"t":(strip(t.group(1)) if t else "(untitled)").rstrip("."),"v":strip(v.group(1)) if v else "","l":link})
        keys=[]
        if a:
            for n in (x.strip() for x in a.group(1).split(",")):
                if not n: continue
                k,disp=parse_author(n)
                if not k: continue
                keys.append(k); namecount[k][disp]+=1
        paper_keys.append(sorted(set(keys)))
    return works, paper_keys, namecount

# ---------- Netzwerk-Daten ----------
def network_data(paper_keys, namecount):
    WAG="n|wagner"
    val=Counter(); wag=Counter(); edge=defaultdict(int)
    for ks in paper_keys:
        for k in ks: val[k]+=1
        if WAG in ks:
            for k in ks:
                if k!=WAG: wag[k]+=1
        for i in range(len(ks)):
            for j in range(i+1,len(ks)):
                edge[(ks[i],ks[j])]+=1
    nodes=[{"id":k,"name":namecount[k].most_common(1)[0][0],"val":val[k],"wag":(0 if k==WAG else wag[k])} for k in val]
    links=[{"source":a,"target":b,"w":w} for (a,b),w in edge.items()]
    return {"nodes":nodes,"links":links}

def person_works(paper_keys):
    pw=defaultdict(list)
    for idx,ks in enumerate(paper_keys):
        for k in ks: pw[k].append(idx)
    return {k:sorted(set(v)) for k,v in pw.items()}

# ---------- Collaboration-Worldmap-Daten ----------
def collab_data(works, paper_keys):
    CW=defaultdict(list); people=defaultdict(set)
    for idx,ks in enumerate(paper_keys):
        cs=set()
        for k in ks:
            C=country_of(k)
            if C: cs.add(C); people[C].add(k)
        for C in cs: CW[C].append(idx)
    cw={c:sorted(set(v)) for c,v in CW.items()}
    cdata={c:{"papers":len(cw[c]),"people":len(people[c])} for c in cw}
    return cdata, works, cw

# ---------- Citation-Worldmap-Daten (OpenAlex) ----------
def author_work_ids():
    ids=[]; cur="*"
    while cur:
        d=oa("/works?filter=author.id:"+AUTHOR_ID+"&select=id&per-page=200&cursor="+urllib.parse.quote(cur))
        ids+=[short_id(w["id"]) for w in d["results"]]
        cur=d["meta"].get("next_cursor")
    return ids
def first_author(w):
    al=w.get("authorships",[])
    if not al: return ""
    nm=(al[0].get("author") or {}).get("display_name","") or ""
    return nm+(" et al." if len(al)>1 else "")
def citation_collect(work_ids):
    cites="|".join(work_ids); works=[]; seen={}; cidx=defaultdict(list); cur="*"; total=0; pages=0
    while cur:
        d=oa("/works?filter=cites:"+cites+"&select=id,display_name,publication_year,doi,authorships&per-page=200&cursor="+urllib.parse.quote(cur))
        for w in d["results"]:
            total+=1; wid=short_id(w["id"])
            if wid not in seen:
                doi=w.get("doi"); link=doi if doi else ("https://openalex.org/"+wid)
                seen[wid]=len(works)
                works.append({"t":w.get("display_name") or "(untitled)","y":w.get("publication_year") or 0,"l":link,"a":first_author(w)})
            ix=seen[wid]; cs=set()
            for a in w.get("authorships",[]):
                for c in (a.get("countries") or []): cs.add(c)
                for inst in (a.get("institutions") or []):
                    if inst.get("country_code"): cs.add(inst["country_code"])
            for cc in cs: cidx[cc].append(ix)
        pages+=1; cur=d["meta"].get("next_cursor")
        print("  Seite "+str(pages)+": "+str(total)+" zitierende Arbeiten", file=sys.stderr)
    return works, cidx, total
def iso_lookup():
    data=http_get(URL_ISO); table={}
    for c in data:
        a2=c.get("cca2"); n3=c.get("ccn3"); nm=(c.get("name") or {}).get("common")
        if a2 and n3: table[a2]=(str(int(n3)), nm or a2)
    return table
def citation_data():
    wids=author_work_ids()
    print("   "+str(len(wids))+" Werke des Autors", file=sys.stderr)
    works, cidx, total = citation_collect(wids)
    iso=iso_lookup()
    cdata={}; cw={}
    for cc,idxs in cidx.items():
        if cc in iso:
            n3,nm=iso[cc]; uniq=sorted(set(idxs))
            cdata[n3]={"name":nm,"count":len(uniq),"iso2":cc}; cw[n3]=uniq
    today=time.strftime("%B %Y")
    foot=("Source: OpenAlex, retrieved "+today+". Counts are works citing Norman Wagner (OpenAlex ID "+AUTHOR_ID+
          ") with at least one author based in that country; a citing work counts once per country. "+str(total)+
          " citing works across "+str(len(cdata))+" countries. Multi-country papers are counted in each country, "
          "so country totals can exceed the number of distinct citing works.")
    return cdata, works, cw, foot

# ---------- Schreiben ----------
def dump(o): return json.dumps(o, ensure_ascii=False)
def main():
    print("Lese index.html ...", file=sys.stderr)
    works, paper_keys, namecount = parse_index()
    print("   "+str(len(works))+" Publikationen", file=sys.stderr)
    print("Lade D3 ...", file=sys.stderr)
    d3=http_get(URL_D3, as_json=False)

    # 1) Netzwerk
    net=tpl(NET_TPL_B64).replace("__D3__", d3).replace("__DATA__", dump(network_data(paper_keys, namecount))).replace("__WORKS__", dump(works)).replace("__PWORKS__", dump(person_works(paper_keys)))
    open(OUT_NET,"w",encoding="utf-8").write(net); print("geschrieben: "+OUT_NET, file=sys.stderr)

    # 2) Collaboration-Worldmap
    print("Lade Weltkarte/TopoJSON ...", file=sys.stderr)
    world=http_get(URL_WORLD, as_json=False); topo=http_get(URL_TOPO, as_json=False)
    cdata, w_works, cw = collab_data(works, paper_keys)
    col=(tpl(COLLAB_TPL_B64).replace("__D3__",d3).replace("__TJ__",topo).replace("__WORLD__",world)
         .replace("__CDATA__",dump(cdata)).replace("__WORKS__",dump(w_works)).replace("__CWORKS__",dump(cw)))
    open(OUT_COLLAB,"w",encoding="utf-8").write(col); print("geschrieben: "+OUT_COLLAB, file=sys.stderr)

    # 3) Citation-Worldmap (OpenAlex)
    print("Hole Zitationsdaten von OpenAlex ...", file=sys.stderr)
    try:
        ccdata, cworks, ccw, foot = citation_data()
        cit=(tpl(CIT_TPL_B64).replace("__D3__",d3).replace("__TJ__",topo).replace("__WORLD__",world)
             .replace("__CDATA__",dump(ccdata)).replace("__WORKS__",dump(cworks)).replace("__CWORKS__",dump(ccw))
             .replace("__FOOT__",foot))
        open(OUT_CIT,"w",encoding="utf-8").write(cit); print("geschrieben: "+OUT_CIT, file=sys.stderr)
    except Exception as e:
        print("   Citation-Worldmap uebersprungen (Fehler: "+str(e)+")", file=sys.stderr)

    print("Fertig.", file=sys.stderr)

if __name__ == "__main__":
    main()
